INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52001, 10, 0, 0, "ペコリーヌの満腹ツインおにぎり", 1, 1, 2, "ペコリーヌの\n満腹ツインおにぎり", "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 500, "500マイルを獲得する。", 51001, 1, 2, "ペコリーヌが丹精込めて握った特大おにぎり。\nごはんは命のエネルギーを体現しているらしい。\n普通の人が満腹に感じる量の倍のサイズの中に\n最高級の具を閉じ込めた【美食殿】らしい一品。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52002, 10, 0, 0, "コッコロのゆるりと休憩サラダ", 3, 1, 2, "コッコロの\nゆるりと休憩サラダ", "このターンに振るダイスの目が必ず「1」になる。さらに、次のターン数のカウントをスキップする。", 500, "500マイルを獲得する。", 51002, 1, 30001, "コッコロが皆のことを思って用意したサラダ。\n栄養バランスも考えられたうえに腹持ちもよく\n味だけではなく見た目にも気を配られている。\n冒険への活力を与えてくれる慈愛溢れる一品。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52003, 10, 0, 0, "キャルの絶品五つ星バーガー", 2, 1, 1, "キャルの\n絶品五つ星バーガー", "このターンに振るダイスの目が必ず「5」になる。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51003, 1, 20004, "キャルが食べたい物を挟み込んだハンバーガー。\n香ばしいパンとお肉の香りが食欲を刺激する。\n魔物でない素材で作られた、冒険中に食べるには\nゴージャスすぎる一品、とキャルは信じている。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52004, 10, 0, 0, "リリのコツコツまい進かしわ餅", 2, 3, 4, "リリのコツコツ\nまい進かしわ餅", "ダイスを3回振るまでの間、ダイスの目が必ず「4」になる。", 500, "800マイルを獲得する。", 51004, 1, 20001, "リリが作った柏餅……の中でも、上手く作れた\n選りすぐりの品。最高の素材を使用した上、\n失敗した分はリリが自分で食べてしまったため\n単価でみるとかなりの高級品となっている。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52005, 11, 0, 0, "クリアの彩り華やかバラエティ弁当", 4, 0, 1, "クリアの彩り華やか\nバラエティ弁当", "ランダムなイベントを発生させる。", 500, "次にダイスを振った際、1マス多く進める。", 51005, 3, 1, "クリアが朝早くから用意した冒険用のお弁当。\nおかずは様々でどれも絶品だが、どんなものが\n入っているかはみんなにも秘密にされているため\n蓋を開けるまでのお楽しみとなっている。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52006, 10, 0, 0, "プレシアの食いしん坊ぶーぶー肉まん", 2, 1, 4, "プレシアの食いしん坊\nぶーぶー肉まん", "このターンに振るダイスの目が「4・5・6」のみになる。", 500, "800マイルを獲得する。", 51006, 1, 20002, "プレシアが選び抜いた具を詰め込んだ肉まん。\n彼女の希望で、通常の肉まんの数倍のサイズに\nなっている。味もボリュームも満点でハッピー\n間違いなしですよ♪とは調理担当クリアの談。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52007, 10, 0, 0, "カヤとイノリの食欲倍増ケバブサンド", 7, 2, 3, "カヤとイノリの\n食欲倍増ケバブサンド", "このターンに振るダイスの目を必ず「3」に、次のターンに振るダイスの目を必ず「6」にする。", 500, "福引券を1枚獲得する。", 51007, 1, 1, "カヤとイノリが弁当代わりに持ってきたケバブ。\nイノリ行きつけの店の硬派な味わいで、ギャング\nとしてのやる気が一人3倍、コンビで6倍となり\n下剋上を成し遂げるパワーが湧く……らしい。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52008, 10, 0, 1, "タマキの金運招くレインボーたい焼き", 5, 0, 2, "タマキの金運招く\nレインボーたい焼き", "次にマイルマスに止まった際の獲得マイルが200%アップする。", 500, "500マイルを獲得する。", 51008, 2, 200, "タマキたちが『ジオ・テオゴニア』に持ち込んだ\nたい焼きの概念が現地の文化と溶け合い生まれた\n魔改造スイーツ。虹色に輝くその甘さは、実に\nランドソルのたい焼きの数倍と言われている。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52009, 10, 1, 0, "クローチェのフルパワーポテトサラダ", 7, 2, 1, "クローチェの\nフルパワーポテトサラダ", "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「8」に、次のターンに振るダイスの目を必ず「1」にする。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51009, 1, 1, "クローチェがフルパワーで作ったポテトサラダ。\n本来はガレットを作ろうとしたが、うっかり\n握り潰してしまったため、軌道修正して仕上げ\nた一品。経緯はともかく味は非常に美味である。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52010, 10, 0, 2, "アヤネとクルミの青空ピクニックセット", 6, 0, 2, "アヤネとクルミの\n青空ピクニックセット", "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計2回止まるまで継続する。", 500, "500マイルを獲得する。", 51010, 2, 1, "アヤネとクルミが二人で用意した特別なランチ\nバスケット。仲間との冒険への希望が詰まった\nご機嫌な料理の数々で、道中の様々な出来事が\n１ランク上のイベントに感じられるようになる。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52011, 10, 0, 0, "リマの不思議なスイートアップル", 7, 2, 3, "リマの不思議な\nスイートアップル", "このターンに振るダイスの目を必ず「2」に、次のターンに振るダイスの目を必ず「7」にする。", 500, "福引券を1枚獲得する。", 51011, 1, 1, "リマがネネカにもらったリンゴで作った秘密の\nスイーツ。爽やかな酸味と濃厚な甘さがまるで\n魔法のようなバランスでお互いを引きたてており\n食べた者をたちまち虜にしてしまうという。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52012, 10, 0, 0, "ニノンのオリジナル一二三寿司", 3, 1, 1, "ニノンのオリジナル\n一二三寿司", "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51012, 1, 30002, "ニノンがジオ・テオゴニアに持ち込んだ特別な\n寿司。厳選された新鮮な魚介を使った逸品だが、\n一部のネタは、寿司のセオリーを逸脱したニノン\n我流のものに仕上がっている。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52013, 10, 0, 0, "クレジッタの開運お菓子盛り合わせ", 8, 0, 4, "クレジッタの開運\nお菓子盛り合わせ", "RANK2のマイルショップを開く。", 500, "800マイルを獲得する。", 51013, 3, 2, "クレジッタが考案した、ジオ・テオゴニアで流通\nしているチョコの貨幣の盛り合わせ。一見すると\n金貨を口に入れるおバカさんではあるが、通貨を\n食べるという背徳感が隠し味となっている。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52014, 11, 0, 0, "リノの「時は金時」かき氷", 9, 2, 1, "リノの\n「時は金時」かき氷", "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 500, "次にダイスを振った際、1マス多く進める。", 51014, 1, 1, "可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52015, 11, 0, 0, "シズルの愛情盛り盛りハンバーグ", 1, 1, 1, "シズルの愛情\n盛り盛りハンバーグ", "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 500, "次にダイスを振った際、1マス多く進める。", 51015, 1, 2, "お姉ちゃんが弟くんのために心を込めて作った\nスペシャルなハンバーグ。アツアツの肉汁と共に\n溢れんばかりの愛が詰まっており、一口食べる\nだけで、走り回りたくなるような美味しさ。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52016, 0, 0, 0, "アオイの疾走サンドイッチ", 2, 1, 0, "アオイの疾走\nサンドイッチ", "このターンに振るダイスの目が必ず「6」になる。", 500, "なし", 51016, 1, 20005, "アオイがお弁当として作ったエルフ伝統の野菜\nサンド。一緒についてきてくれる最高の友だち\nの助言により、どんなに深い森の中でも全速力\nで駆け抜けることができるらしい。（アオイ談）", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52017, 10, 1, 0, "クウカの緊縛触手活け造り", 2, 2, 5, "クウカの緊縛\n触手活け造り", "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で2000マイルを獲得する。", 500, "なし", 51017, 1, 1, "数多くのドM妄想をしてきたクウカの中で最近の\nマイブームである触手をモチーフとした活造り。\n新鮮な蛸足が、濃厚なうま味と共に物理的に絡み\n付き身も心も縛りあげられる様な体験ができる。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52018, 10, 0, 0, "ランファの世話焼き三昧肉じゃが", 2, 1, 6, "ランファの世話焼き三昧肉じゃが", "このターンに振るダイスの目が必ず「3」になる。", 500, "1000マイルを獲得する。", 51018, 1, 20006, "コッコロの指導により料理の腕を上げたランファ\nが手作りした肉じゃが。まだ改善の余地はある\nものの、不器用なランファが誰かのために積み\n重ねた努力を思うととてもおいしく味わえる。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52019, 0, 0, 0, "ワカナの節約腹八分目カレー", 2, 1, 0, "ワカナの節約腹八分目カレー", "このターンに振るダイスの目が必ず「8」になる。", 500, "なし", 0, 1, 20007, "バンディ・シスターズの昨夜の夕食カレー。作り\n過ぎて食べきれずにいたものをワカナがお裾分け\nしてくれた。寝かされていたためしっかりと味の\n染みた、極上の二日目カレーとなっている。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52020, 11, 0, 0, "リノの「時は金時」かき氷", 9, 2, 1, "リノの\n「時は金時」かき氷", "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 500, "次にダイスを振った際、1マス多く進める。", 51014, 2, 1, "可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52021, 10, 0, 0, "カスミの真実見抜くボンボン・ショコラ", 9, 3, 7, "カスミの真実見抜く\nボンボン・ショコラ", "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", 500, "	平凡な未鑑定トレジャーを2個獲得する。", 51021, 2, 2, "綺麗な装飾箱に納められたボンボン・ショコラ。\nそのほろ苦さを秘めた濃密な甘さが灰色の脳細胞\nに働きかける時、名探偵の鋭い推理が隠された\n謎を全て白日の下へと晒し、事件を解決へ導く。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52022, 0, 0, 0, "アキノのゲヘニアンチキンプレート", 2, 3, 0, "アキノのゲヘニアン\nチキンプレート", "ダイスを3回振るまでの間、「5と6」の⽬が出る確率が3倍になる。", 500, "なし", 51022, 1, 20008, "アキノがジオ・ゲヘナで仕入れてきたスパイスを\n使用した、お洒落で豪華なチキンプレート。牧場\n特製ヨーグルトソースと奏でる刺激的な味わいは\nまさに二つの世界の奇跡のマリアージュである。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52023, 10, 1, 0, "ミミのコロコロお手玉おにぎり", 7, 2, 1, "ミミのコロコロ\nお手玉おにぎり", "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「6」に、次のターンに振るダイスの目を必ず「3」にする。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51023, 1, 1, "ミミが、ジオ・ゲヘナで助けてくれたお姉さん達\nのことを思い作ったおにぎり。それぞれ異なる\n味付けがされているが、ミミの願い通りお互いに\nケンカをせず仲良くハーモニーを奏でている。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52024, 11, 0, 0, "アユミの隠密ガトーインビジブル", 8, 0, 3, "アユミの隠密\nガトーインビジブル", "RANK2のマイルショップを開く。", 500, "次にダイスを振った際、3マス多く進める。", 51024, 3, 2, "気が付くとリリの手元にあった不思議なお菓子。\n一見普通のケーキだが、内部に様々な具材が\n隠れるように入っている。複雑で重層的な\n味わいを見せる様は、まるで誰かさんのよう。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52025, 0, 0, 0, "アネモネの花爛漫ステーキサラダ", 9, 1, 0, "アネモネの\n花爛漫ステーキサラダ", "「マイルマス」「トレジャーマス」をスキップして移動できる。効果は1ターンの間継続する。", 500, "なし", 51025, 2, 3, "アネモネが世話する秘密の菜園の野菜を使った\nサラダ。栄養を重視するアネモネは草食獣の肉を\n野菜と解釈、当初は野菜の上に肉を置いただけ\nであったが、ネラの指導で盛り付け直された。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52026, 10, 0, 0, "アンナの煉獄蕃茄煮混沌卵", 4, 0, 8, "アンナの\n煉獄蕃茄煮混沌卵", "ランダムなイベントを発生させる。", 500, "福引券を2枚獲得する。", 51026, 3, 1, "ジオ・ゲヘナを探索中の冥姫たちが現地で採取\nしたスパイスで味付けした一皿。赤く煮え滾る\nソースは刺激的かつ非常に奥深い味わいで未知の\n大地の如く冒険者たちをその深奥へと誘う。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52027, 0, 0, 0, "ユイの栄養満点まごころ弁当", 2, 2, 0, "ユイの\n栄養満点まごころ弁当", "ダイスを2回振るまでの間、ダイスの目が必ず「5」になる。", 500, "なし", 51027, 1, 20004, "ユイが食べる人のことを考え、心を込めて作った\nお弁当。程よいサイズのお弁当箱に愛情と手間暇\nをたっぷりとかけた極上の料理が詰まっており、\n食べた者の心と胃袋を優しく満たしてくれる。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52028, 10, 0, 0, "リンのナッツ入りぐうたらあんパン", 2, 1, 9, "リンの\nナッツ入りぐうたらあんパン", "このターンに振るダイスの目が「1・2」のみに\nなる代わりに、その場で福引券を3枚獲得する。", 500, "なし", 51028, 1, 30003, "リンからもらった非常食のあんパン。ナッツが\n練り込まれクランチな食感で食べ飽きない。\nゲームのため部屋に引きこもる際のお供であり、\n必要な栄養素が全て賄える完全栄養食、らしい。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52029, 0, 0, 0, "シェフィの氷晶煌めく手作りアイス", 3, 1, 0, "シェフィの\n氷晶煌めく手作りアイス", "このターンに振るダイスの目が必ず「2」になる。さらに、次のターン数のカウントをスキップする。", 500, "なし", 51029, 1, 30004, "シェフィが自身の魔力の氷を使い作ったアイス。\nペコリーヌにねだられて作ったものだがキャル達\nにも好評である。コッコロ曰くひんやりしている\nのに食べると心が温かくなってきます、との事。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52030, 0, 0, 0, "ミソラの気まぐれ味噌ラーメン★", 12, 3, 0, "ミソラの\n気まぐれ味噌ラーメン★", "3ターンの間、すべての「マイルマス」をランク3の「トレジャーマス」に変化させる。", 500, "なし", 51030, 3, 1, "ミソラが作ったラーメン。適当に言った好きな物\nをランファが憶えていたために、材料を用意され\n仕方なく作ったものだが味はイイコト級の一品。\n美味しそうに食べられるのは嫌いではない様子。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52031, 0, 0, 0, "イロハの最強クワガタゼリー（人間用）", 2, 1, 0, "イロハの\n最強クワガタゼリー（人間用）", "このターンに振るダイスの目が「1・6・6・6・8・8」になる。", 500, "なし", 51031, 1, 20009, "イロハがいつも持ち歩いているカラフルなゼリー\n…なのだがアルケス錬金堂で作られたクワガタ用\n餌ゼリーとそっくりな見た目をしている。甘くて\n美味しいが、人間用か尋ねると目を逸らされる。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52032, 11, 0, 0, "グレイスの目ん玉飛び出るカップケーキ", 9, 2, 3, "グレイスの\n目ん玉飛び出るカップケーキ", "料理マスをスキップして移動できる。効果は2ターンの間継続する。", 500, "次にダイスを振った際、3マス多く進める。", 51032, 2, 4, "グレイスお手製のカップケーキ。ショッキングな\n見た目に全振り…と思わせて目玉も食べることが\n可能で大変美味…と思わせて一部だけ魂消るほど\n甘い部分がある。原材料は頑なに秘されている。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52033, 0, 0, 0, "ソノの今日は特別ご褒美オムライス", 8, 0, 0, "ソノの今日は特別ご褒美オムライス", "RANK3のマイルショップを開く。", 500, "なし", 51033, 3, 3, "ソノが作ったオムライス。イロハの大好物であり\n家庭の味。普段は面倒くさがりやらないがイロハ\nが良い子の時はケチャップでクワガタを描いて\nあげている。その時は普段より美味しいらしい。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52034, 10, 0, 0, "ジータのグリルド・グラッジチャンク", 9, 2, 1, "ジータの\nグリルド・グラッジチャンク", "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51034, 2, 1, "そのあまりの美味さと、ほとばしるカロリーから\n悪意の塊、という物騒な名が付けられた肉料理。\nこの肉を集められるかが騎空士としての力量を\n示すため、ジータは大量に集めたがっている。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52035, 10, 0, 0, "ルイズマリーの成功しすぎてるフライ", 4, 0, 10, "ルイズマリーの\n成功しすぎてるフライ", "ランダムなイベントを発生させる。", 500, "貴重な未鑑定トレジャーを1個獲得する。", 51035, 3, 1, "ルイズマリーが祖母のレシピを忠実に再現した\n最高傑作。精緻な調合と温度管理が生み出す衣と\n身のサクフワは錬金技術の到達点と言われている\nが、ただの料理なのではとの意見も絶えない。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52036, 0, 1, 0, "ホウオウの食べる権利をあげます！饅頭", 7, 3, 0, "ホウオウの\n食べる権利をあげます！饅頭", "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「12」に、次とさらにその次のターンに振るダイスの目を必ず「1」にする。", 500, "なし", 51036, 1, 1, "ジオ・ゲヘナの空の覇者にして煉華のホウオウが\n己への信仰心を集めるべく作らせたお菓子。中の\n餡はしっとり甘く、上品な味わい。ジオ・ゲヘナ\n銘菓の名を恣にする日も近い、かもしれない。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52037, 10, 0, 1, "魔法少女ナナカちゃんウエハース", 6, 0, 11, "魔法少女\nナナカちゃんウエハース", "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計1回止まるまで継続する。", 500, "平凡な未鑑定トレジャーを3個獲得する。", 51037, 2, 1, "ナナカ考案＆監修のウエハース。おまけシールの\nコレクション性を高くした結果ランドソル中で\n大ブーム…だが肝心の菓子が棄てられる事態に。\n解決のため、王女が自ら口を開いたのだった。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52038, 10, 0, 0, "アリサがお届け♪リノセウスの包み焼き", 1, 1, 3, "アリサがお届け♪\nリノセウスの包み焼き", "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 500, "福引券を1枚獲得する。", 51038, 1, 2, "アリサ特製の包み焼き。伝承の怪物とよく似た\n魔物を材料にしているため、いつしかその怪物と\n同じ名で呼ばれるようになったという。鋭い鎌と\n火傷に気を付けながら、熱々を召し上がれ。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52039, 0, 0, 0, "イリヤの†ブラッディ†トマトジュース", 12, 2, 0, "イリヤの†ブラッディ†\nトマトジュース", "2ターンの間、すべての「マイルマス」をランク3の「ショップマス」に変化させる。", 500, "なし", 51039, 3, 2, "イリヤの愛飲する赤く鮮やかなトマトジュース。\n伝説の吸血鬼に相応しいクオリティを、と求めた\n末に辿り着いた究極の逸品。しかしお値段も相応\nに張るため、特別な時にしか飲めないらしい。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52040, 11, 0, 0, "マツリの活力源～騎士団遠征プレート～", 9, 3, 2, "マツリの活力源\n～騎士団遠征プレート～", "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", 500, "次にダイスを振った際、2マス多く進める。", 51040, 2, 2, "【王宮騎士団】遠征時の定番メニューにマツリが\nアレンジを加え調理したプレート。苦手な野菜を\nなくしてお肉倍増を目論んだのが配膳前にバレ、\nジュンの指導できちんと野菜も入れさせられた。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52041, 10, 1, 0, "ヴァンピィちゃんのさいきょースープ", 7, 2, 1, "ヴァンピィちゃんの\nさいきょースープ", "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「7」に、次のターンに振るダイスの目を必ず「2」にする。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51041, 1, 1, "ヴァンピィがよく振舞ってくれる特製スープ。\nどうやら家庭料理のようで、素朴な味わいが\n人々を郷愁へと誘う。昔誰かと並んで一緒に\n肉団子を作ったような…とはヴァンピィの言葉。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52042, 0, 0, 0, "アイラのみんなで飲みたい赤麦しゅわ", 2, 2, 0, "アイラのみんなで\n飲みたい赤麦しゅわ", "ダイスを2回振るまでの間、出る目が「4・5・6」のみになる", 500, "なし", 51042, 1, 20002, "アイラが愛する赤麦しゅわ。彼女の熱い要望で\n酩酊感ゼロの子供向けも生産開始した。曰くこの\n美味しさを広めるためとのことだが、本当は単に\n老若男女皆で楽しく飲みたいだけかもしれない。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52043, 10, 1, 0, "レイの釣りたて鮮魚七輪塩焼き", 2, 2, 12, "レイの釣りたて\n鮮魚七輪塩焼き", "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で貴重な未鑑定トレジャーを3個獲得する。", 500, "なし", 51043, 1, 1, "レイが釣った魚の塩焼き。試行錯誤の末に理想の\n塩と火の加減にたどり着いた。調理は真剣勝負で\n釣りと同様、己の心との戦いだという。レイも\n時々、集中しすぎて仲間に心配されているとか。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52044, 10, 0, 0, "ユキノ製ごろっと果実のかちこち氷菓子", 3, 1, 3, "ユキノ製ごろっと果実の\nかちこち氷菓子", "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", 500, "福引券を1枚獲得する。", 51044, 1, 30002, "ユキノが偶然生み出した、青果実のアイスバー。\n元は誤って凍らせたものだが爽やかな味が好評で\nなんと久遠氷河を代表する手土産に。伸び続ける\n売り上げに本人が一番溶けそうになっている。", 2);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52045, 10, 0, 0, "サレンの思い出ぎっしり焼きそばパン", 9, 3, 4, "サレンの思い出ぎっしり\n焼きそばパン", "「ショップマス」「ミニゲームマス」「イベントマス」をスキップして移動できる。効果は3ターンの間継続する。", 500, "800マイルを獲得する。", 51045, 2, 5, "サレンが作った思い出の焼きそばパン。どっしり\nしたボリュームある炭水化物×炭水化物の信頼感\nで皆を笑顔に変える。専用の皿に盛り付けたら見\n栄えも十分。カロリーは気にしないのがお作法。", 3);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52046, 0, 0, 0, "アラクネの肉マシマシマシ炒め野菜入り", 9, 3, 0, "アラクネの肉マシマシマシ炒め\n野菜入り", "マイルマスをスキップして移動できる。効果は3ターンの間継続する。", 500, "なし", 51046, 2, 1, "アラクネが初めて覚えた料理。周囲の人々が自分\nより小さいのは小食が理由と思っているらしく、\nたくさん食べて大きくなってほしいという優しさ\nから、超ボリュームなデカ盛り仕様となった。", 1);
INSERT INTO `v1_c30b93c9acc066b8c539df6faa57ec885ff0b442c1bfec5ab7afa49fddda4605` VALUES (52047, 10, 0, 0, "シナツの極うな重　韋駄天仕上げ", 1, 1, 1, "シナツの極うな重\n韋駄天仕上げ", "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 500, "平凡な未鑑定トレジャーを1個獲得する。", 51047, 1, 2, "胃に入れば何でも同じ、が信条のシナツが自分で\n釣った鰻で拵えたうな重。レイの協力のもと練習\nを重ね、見た目も味も合格点に到達した。一番\n苦労したのは調理場を破壊しない力加減だとか。", 1);
